/**
 * InstructionsLoaded Dispatcher — real single-file payload (#2475)
 *
 * The real CC InstructionsLoaded event fires ONCE PER FILE with
 * { file_path, memory_type, load_reason }. The previous dispatcher read a
 * fabricated `files_loaded` array (0 handlers ever ran) and returned
 * additionalContext (stripped by bin/output-guard.mjs for this event).
 *
 * Now runs only the PER-FILE handlers:
 * 1. Token Budget      — accumulate byte sizes in session state, warn once via systemMessage
 * 2. Smart Suggestions — accumulate loaded rule names, suggest missing rules once via systemMessage
 *
 * The whole-set handlers (priority-map, content-dedup, rule-conflicts,
 * drift-detection, debt-surfacer) moved to SessionStart — see
 * session-rules-audit.ts — where the full rule set exists on disk AND
 * additionalContext is honored.
 *
 * Output contract: NEVER outputPromptContext here. Silent success by default;
 * user-facing findings surface via systemMessage.
 */

import type { HookInput, HookResult, HookContext, InstructionsLoadedInput } from '../types.js';
import { isInstructionsLoadedInput } from '../types.js';
import { outputSilentSuccess } from '../lib/common.js';
import { tokenBudgetTracker } from './token-budget-tracker.js';
import { smartRuleSuggestions } from './smart-suggestions.js';
import { NOOP_CTX } from '../lib/context.js';

const HOOK_NAME = 'instructions-loaded-dispatcher';

type Handler = (input: InstructionsLoadedInput) => string | null;

const HANDLERS: Array<{ name: string; fn: Handler }> = [
  { name: 'Token Budget', fn: tokenBudgetTracker },
  { name: 'Smart Suggestions', fn: smartRuleSuggestions },
];

export function instructionsLoadedDispatcher(input: HookInput, ctx: HookContext = NOOP_CTX): HookResult {
  if (!isInstructionsLoadedInput(input)) {
    ctx.log(HOOK_NAME, 'No file_path in InstructionsLoaded payload, skipping');
    return outputSilentSuccess();
  }

  ctx.log(HOOK_NAME, `Instruction file loaded: ${input.file_path} (${input.memory_type ?? 'unknown'}/${input.load_reason ?? 'unknown'})`);

  const messages: string[] = [];

  for (const handler of HANDLERS) {
    try {
      const result = handler.fn(input);
      if (result) messages.push(result);
    } catch (err) {
      ctx.log(HOOK_NAME, `${handler.name} failed: ${err}`, 'warn');
    }
  }

  if (messages.length === 0) {
    return outputSilentSuccess();
  }

  // systemMessage is the ONLY user-facing channel on this event —
  // additionalContext is stripped by output-guard (#2475).
  return {
    continue: true,
    suppressOutput: true,
    systemMessage: messages.join('\n'),
  };
}
